import React, { useContext, useState } from "react";
import { login } from "../lib/api";
import LoginForm from "../Components/Forms/LoginForm";
import AuthContext from "../store/auth-context";
import Banner from "../Components/Banner";
import { useTranslation } from "react-i18next";

const LoginPage = () => {
  const [isLoginSuccess, setIsLoginSuccess] = useState(false);
  const [loginMessage, setLoginMessage] = useState("");
  const authCtx = useContext(AuthContext);
  const { t } = useTranslation();

  const onSubmit = (loginRequest, formikHelpers) => {
    setTimeout(() => {
      login(loginRequest)
        .then(res => { setIsLoginSuccess(true); setLoginMessage(`${t("signedInAs")} ${res.userName}`); setTimeout(() => authCtx.login(res), 2000); })
        .catch(error => {
          if (error.message.includes("password")) formikHelpers.setFieldError("invalidPassword", t("validation:invalidPassword"));
          else formikHelpers.setFieldError("invalidUsername", t("validation:invalidUsername"));
        })
        .finally(() => formikHelpers.setSubmitting(false));
    }, 1000);
  };

  return (
    <div className="ink-page page-fade-in">
      <div className="ink-form-wrap">
        <div style={{ width: "100%", maxWidth: 480 }}>
          <LoginForm isSubmitted={isLoginSuccess} onSubmit={onSubmit} />
          {isLoginSuccess && <Banner className="text-success border-success mt-4" message={loginMessage} />}
        </div>
      </div>
    </div>
  );
};
export default LoginPage;
